// PDU Model
package circuit

import (
	"context"

	"github.com/arminguenther/xeruspower-go/v40020/event/userevent"
	"github.com/arminguenther/xeruspower-go/v40020/idl"
	"github.com/arminguenther/xeruspower-go/v40020/pdumodel/pole"
	"github.com/arminguenther/xeruspower-go/v40020/sensors/numericsensor"
)

const (
	ERR_INVALID_PARAM      int32 = 1 // Invalid parameters
	ERR_METER_CHANNEL_BUSY int32 = 2 // Meter channel already in use
)

// BCM circuit
type Circuit interface {
	idl.Object

	// Retrieve the circuit configuration.
	//
	//	@return Circuit configuration
	GetConfig(ctx context.Context) (Config, error)

	// Retrieve the circuit sensors.
	//
	//	@return Circuit sensors
	GetSensors(ctx context.Context) (Sensors, error)

	// Retrieve the list of circuit poles.
	//
	//	@return List of circuit poles
	GetPoles(ctx context.Context) ([]pole.Pole, error)

	// Get the circuit settings.
	//
	//	@return Circuit settings
	GetSettings(ctx context.Context) (Settings, error)

	// Change the circuit settings.
	//
	//	@param settings  New circuit settings
	//
	//	@return 0 if OK
	//	@return 1 if any parameters are invalid
	//	@return 2 if the requested meter channel is already in used
	SetSettings(ctx context.Context, settings Settings) (int32, error)
}

// Circuit type
type Type int

const (
	ONE_PHASE_LN  Type = iota // One-phase line-neutral
	ONE_PHASE_LL              // One-phase line-line
	ONE_PHASE_LLN             // One-phase line-line-neutral
	THREE_PHASE               // Three-phase
)

// Circuit configuration
type Config struct {
	Position int32 // Circuit position of first pole
	Type     Type  // Circuit type
}

// Circuit sensors
type Sensors struct {
	Current                 numericsensor.NumericSensor // RMS current sensor
	ActivePower             numericsensor.NumericSensor // Active power sensor
	ReactivePower           numericsensor.NumericSensor // Reactive power sensor
	ApparentPower           numericsensor.NumericSensor // Apparent power sensor
	PowerFactor             numericsensor.NumericSensor // Power factor sensor
	PhaseAngle              numericsensor.NumericSensor // Phase angle sensor
	DisplacementPowerFactor numericsensor.NumericSensor // Displacement power factor
	ActiveEnergy            numericsensor.NumericSensor // Active energy sensor
	UnbalancedCurrent       numericsensor.NumericSensor // Current unbalance sensor
	CrestFactor             numericsensor.NumericSensor // Crest factor sensor
	ActivePowerDemand       numericsensor.NumericSensor // Active power demand
}

// Circuit pole settings
type PoleSettings struct {
	Line         pole.PowerLine // Power line
	MeterChannel int32          // Meter channel index; -1 for unmetered poles
}

// Circuit settings
type Settings struct {
	Name         string         // Circuit name
	Rating       int32          // Circuit current rating
	CtRating     int32          // Current transformer rating
	PoleSettings []PoleSettings // Pole settings (excluding Neutral)
}

// Event: Circuit settings have changed
type SettingsChangedEvent interface {
	userevent.UserEvent
	OldSettings() Settings // Settings before change
	NewSettings() Settings // Settings after change
	isSettingsChangedEvent()
}
